import{c as o,Q as e,j as s,m as t}from"./chunks/framework.CPTW7DhK.js";const u=JSON.parse('{"title":"Impressoras Homologadas","description":"Lista completa de impressoras fiscais e não fiscais homologadas com os sistemas Desbravador","frontmatter":{"title":"Impressoras Homologadas","description":"Lista completa de impressoras fiscais e não fiscais homologadas com os sistemas Desbravador","audience":"Cliente / Equipe de TI / Fornecedor de hardware","updated":"2026-05-24T00:00:00.000Z"},"headers":[],"relativePath":"perifericos/impressoras-homologadas.md","filePath":"perifericos/impressoras-homologadas.md","lastUpdated":null}'),r={name:"perifericos/impressoras-homologadas.md"};function i(d,a,n,c,m,l){return e(),s("div",null,[...a[0]||(a[0]=[t('<h1 id="impressoras-homologadas" tabindex="-1">Impressoras Homologadas <a class="header-anchor" href="#impressoras-homologadas" aria-label="Permalink to &quot;Impressoras Homologadas&quot;">​</a></h1><blockquote><p>ℹ️ Esta é uma página compartilhada entre todos os sistemas Desbravador. Última atualização: 24/05/2026.</p></blockquote><hr><h2 id="impressoras-fiscais-ecf" tabindex="-1">Impressoras Fiscais (ECF) <a class="header-anchor" href="#impressoras-fiscais-ecf" aria-label="Permalink to &quot;Impressoras Fiscais (ECF)&quot;">​</a></h2><p>Impressoras Fiscais, também conhecidas como ECF (Emissores de Cupons Fiscais), são equipamentos homologados pela Receita Federal para emissão do cupom fiscal nas vendas realizadas. Sua utilização é obrigatória nos estabelecimentos que operam sob o regime de ECF.</p><blockquote><p>ℹ️ <strong>Recomendação</strong> — Impressoras de pedido de consumo (cozinha, bar, setor de preparo) devem ser configuradas em rede (TCP/IP), garantindo maior estabilidade, facilidade de cabeamento e suporte a múltiplos pontos de envio simultâneos.</p></blockquote><table tabindex="0"><thead><tr><th>Fabricante</th><th>Modelo</th></tr></thead><tbody><tr><td><strong>Bematech</strong></td><td>MP-2000 TH FI</td></tr><tr><td><strong>Bematech</strong></td><td>MP-2100 TH FI</td></tr><tr><td><strong>Bematech</strong></td><td>MP-3000 TH FI</td></tr><tr><td><strong>Bematech</strong></td><td>MP-4000 TH FI</td></tr><tr><td><strong>Bematech</strong></td><td>MP-4200 TH FI</td></tr><tr><td><strong>Bematech</strong></td><td>MP-4200 TH FI II</td></tr><tr><td><strong>Daruma</strong></td><td>FS 600</td></tr><tr><td><strong>Daruma</strong></td><td>FS 700 H/L</td></tr><tr><td><strong>Daruma</strong></td><td>FS 700 Mach</td></tr><tr><td><strong>Daruma</strong></td><td>Mach 1 / 2 / 3</td></tr><tr><td><strong>Elgin</strong></td><td>FIT 1E</td></tr><tr><td><strong>Epson</strong></td><td>TM-88 FB / II / III</td></tr><tr><td><strong>Epson</strong></td><td>T81 FB II / III</td></tr><tr><td><strong>Epson</strong></td><td>TM-T800F</td></tr><tr><td><strong>Epson</strong></td><td>TM-T900F</td></tr><tr><td><strong>Sweda</strong></td><td>ST 120</td></tr><tr><td><strong>Sweda</strong></td><td>ST 200</td></tr></tbody></table><hr><h2 id="impressoras-nao-fiscais" tabindex="-1">Impressoras Não Fiscais <a class="header-anchor" href="#impressoras-nao-fiscais" aria-label="Permalink to &quot;Impressoras Não Fiscais&quot;">​</a></h2><p>Impressoras não fiscais são utilizadas para emissão de CF-e (Cupom Fiscal Eletrônico), NFC-e (Nota Fiscal de Consumidor Eletrônica), recibos, comprovantes de TEF e RPS. São o padrão para novos projetos em substituição às ECFs, conforme a transição do modelo fiscal brasileiro.</p><blockquote><p>ℹ️ A Desbravador não restringe o uso a modelos específicos de impressoras não fiscais — o sistema é adaptável a qualquer marca ou modelo que atenda aos requisitos técnicos de compatibilidade. Os fabricantes listados abaixo possuem ampla compatibilidade comprovada em campo.</p></blockquote><h3 id="recomendacoes-tecnicas" tabindex="-1">Recomendações Técnicas <a class="header-anchor" href="#recomendacoes-tecnicas" aria-label="Permalink to &quot;Recomendações Técnicas&quot;">​</a></h3><p>Ao adquirir impressoras não fiscais, observar os seguintes critérios:</p><ul><li>Conectividade USB ou Rede TCP/IP — evitar interface serial para novos projetos.</li><li>Suporte ao protocolo de controle <strong>ESC/POS</strong>.</li><li>Drivers disponíveis e homologados para Windows 10 e Windows 11.</li><li>Para uso em caixa ou balcão com alto volume de impressão: velocidade mínima de <strong>200 mm/s</strong>.</li><li>Para uso em KDS ou ambiente de cozinha: modelos com resistência a vapor, calor e respingos.</li></ul><h3 id="fabricantes-com-ampla-compatibilidade" tabindex="-1">Fabricantes com Ampla Compatibilidade <a class="header-anchor" href="#fabricantes-com-ampla-compatibilidade" aria-label="Permalink to &quot;Fabricantes com Ampla Compatibilidade&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fabricante</th><th>Observação</th></tr></thead><tbody><tr><td><strong>Epson</strong></td><td>Ampla linha de modelos comprovados; suporte ESC/POS nativo</td></tr><tr><td><strong>Bematech</strong></td><td>Compatibilidade consolidada; drivers estáveis para Windows 10/11</td></tr><tr><td><strong>Daruma</strong></td><td>Boa compatibilidade na linha fiscal e não fiscal</td></tr><tr><td><strong>Elgin</strong></td><td>Compatível; verificar modelo específico com a Desbravador</td></tr><tr><td><strong>Sweda</strong></td><td>Compatível; verificar modelo específico com a Desbravador</td></tr><tr><td><strong>Gertec</strong></td><td>Compatível; verificar modelo específico com a Desbravador</td></tr></tbody></table><blockquote><p>⚠️ <strong>Atenção</strong> — Para modelos não listados ou equipamentos de fabricantes não relacionados acima, consulte a equipe Desbravador antes da aquisição. A compatibilidade depende do protocolo de comunicação e dos drivers disponíveis para o sistema operacional em uso.</p></blockquote><hr><h2 id="observacoes-gerais" tabindex="-1">Observações Gerais <a class="header-anchor" href="#observacoes-gerais" aria-label="Permalink to &quot;Observações Gerais&quot;">​</a></h2><ul><li>Impressoras ECF são equipamentos legados — novos estabelecimentos devem avaliar a adoção de impressoras não fiscais compatíveis com CF-e ou NFC-e, conforme a legislação fiscal aplicável ao seu estado e regime tributário.</li><li>A manutenção e o lacre de impressoras fiscais (ECF) são de responsabilidade do estabelecimento e devem ser realizados por credenciados autorizados pela Secretaria da Fazenda.</li><li>Em caso de substituição de impressora em ambiente produtivo, verificar a necessidade de reconfiguração no sistema antes da troca.</li></ul><hr><h2 id="contato-e-suporte" tabindex="-1">Contato e Suporte <a class="header-anchor" href="#contato-e-suporte" aria-label="Permalink to &quot;Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas sobre compatibilidade ou homologação de novos modelos, entre em contato com a equipe técnica da Desbravador.</p>',24)])])}const b=o(r,[["render",i]]);export{u as __pageData,b as default};
